#include<bits/stdc++.h>
#define ll long long
using namespace std;
const int MAXN=1e3+5;
int m,n,fa[MAXN],ans;
int find(int p){
	if(p==fa[p])return fa[p];
	else return fa[p]=find(fa[p]);
}void f(int x,int y){if(find(x)!=find(y))++ans,fa[find(x)]=fa[find(y)];}
int main(void){
	//freopen("P1536.in","r",stdin);
	//freopen("P1536.out","w",stdout);
	while(true){
		ans=0,scanf("%d",&n);
		if(n==0)break;scanf("%d",&m);
		for(int i=1;i<=n;++i)fa[i]=i;
		for(int i=1,x,y;i<=m;i++){scanf("%d%d",&x,&y);f(x,y);}
		printf("%d\n",n-1-ans);
	}return false;
}
